import socket
import threading
import json

# Constants
SERVER_IP = '127.0.0.1'
SERVER_PORT = 54321
MAX_PLAYERS = 100
UPDATE_INTERVAL = 0.1

# Player class to store player data
class Player:
    def __init__(self, player_id, x, y, z):
        self.player_id = player_id
        self.x = x
        self.y = y
        self.z = z

# Broadcast game state to all connected clients
def broadcast_game_state(clients):
    players_data = [player.__dict__ for player in players.values()]
    message = {
        'type': 'update',
        'data': players_data
    }
    for client in list(clients):
        try:
            client.sendall(json.dumps(message).encode('utf-8'))
        except:
            clients.remove(client)

# Handle client connections and messages
def handle_client(client, player_id):
    while True:
        try:
            message = client.recv(1024)
            if not message:
                break

            # Update player position (simplified for example)
            data = json.loads(message.decode('utf-8'))
            players[player_id].x = data['x']
            players[player_id].y = data['y']
            players[player_id].z = data['z']

        except:
            break

    clients.remove(client)

# Main server setup
def start_server():
    server = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
    server.bind((SERVER_IP, SERVER_PORT))
    server.listen(MAX_PLAYERS)
    print(f"Server started on {SERVER_IP}:{SERVER_PORT}")

    clients = []
    player_id = 0

    while True:
        client, addr = server.accept()
        clients.append(client)
        players[player_id] = Player(player_id, 0, 0, 0)
        threading.Thread(target=handle_client, args=(client, player_id)).start()
        player_id += 1

        if len(clients) >= MAX_PLAYERS:
            break

    # Periodically broadcast game state
    while True:
        broadcast_game_state(clients)
        threading.Event().wait(UPDATE_INTERVAL)

if __name__ == '__main__':
    start_server()